import React, { useState, useEffect } from "react";

export default function Home() {
  const [gas, setGas] = useState(430);
  const [tds, setTDS] = useState(300);
  const [temp, setTemp] = useState(27.5);
  const [ph, setPH] = useState(6.8);
  const [red, setRed] = useState(120);
  const [green, setGreen] = useState(220);
  const [blue, setBlue] = useState(85);

  useEffect(() => {
    const interval = setInterval(() => {
      setRed(Math.floor(Math.random() * 256));
      setGreen(Math.floor(Math.random() * 256));
      setBlue(Math.floor(Math.random() * 256));
      setGas(Math.floor(Math.random() * 600));
      setTDS(Math.floor(Math.random() * 600));
      setTemp((Math.random() * 10 + 25).toFixed(1));
      setPH((Math.random() * 4 + 4.5).toFixed(2));
    }, 4000);

    return () => clearInterval(interval);
  }, []);

  const font = "Times New Roman, serif";

  const cardStyle = {
    fontFamily: font,
    backgroundColor: "#f3e5f5",
    border: "2px solidrgb(139, 76, 150)",
    borderRadius: "15px",
    padding: "20px",
    width: "100%",
    maxWidth: "400px",
    margin: "20px auto",
    boxShadow: "0 4px 15px rgba(106, 27, 154, 0.2)",
    textAlign: "center",
  };

  const labelStyle = {
    fontWeight: "bold",
    fontSize: "20px",
    color: "#4a148c",
    marginBottom: "5px",
  };

  const valueBox = {
    backgroundColor: "#d1c4e9",
    color: "#2e003e",
    padding: "12px 20px",
    borderRadius: "10px",
    fontWeight: "bold",
    fontSize: "22px",
    marginBottom: "10px",
  };

  const rangeText = {
    fontSize: "16px",
    fontWeight: "normal",
    marginBottom: "5px",
    color: "#5e35b1",
  };

  const badge = (status) => ({
    padding: "6px 14px",
    borderRadius: "20px",
    fontWeight: "bold",
    fontSize: "15px",
    color: "#fff",
    backgroundColor: status === "Good" ? "#388e3c" : "#e53935",
    display: "inline-block",
  });

  const sectionHeader = {
    fontFamily: font,
    fontSize: "32px",
    fontWeight: "bold",
    textAlign: "center",
    margin: "30px 0 20px",
    color: "#311b92",
  };

  const wrapper = {
    fontFamily: font,
    background: "linear-gradient(to bottom right, #ede7f6,rgb(224, 179, 231))",
    minHeight: "100vh",
    padding: "30px 10px",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
  };

  const statusChecks = {
    gas: { value: gas, min: 0, max: 350 },
    tds: { value: tds, min: 0, max: 300 },
    temp: { value: temp, min: 20, max: 35 },
    ph: { value: ph, min: 6.5, max: 8.5 },
    red: { value: red, min: 100, max: 255 },
    green: { value: green, min: 100, max: 255 },
    blue: { value: blue, min: 100, max: 255 },
  };

  const getStatus = (sensor) => {
    const { value, min, max } = statusChecks[sensor];
    return value >= min && value <= max ? "Good" : "Bad";
  };

  return (
    <div style={wrapper}>
      <h1 style={sectionHeader}>🧪 FoodScan Dashboard</h1>

      {[
        { label: "🌫️ Gas Sensor", value: gas, unit: "ppm", range: "≤ 350", key: "gas" },
        { label: "💧 TDS Sensor", value: tds, unit: "ppm", range: "≤ 300", key: "tds" },
        { label: "🌡️ Temperature", value: temp, unit: "°C", range: "20–35°C", key: "temp" },
        { label: "🧪 pH Value", value: ph, unit: "", range: "6.5–8.5", key: "ph" },
        { label: "🔴 Red", value: red, unit: "", range: "≥ 100", key: "red" },
        { label: "🟢 Green", value: green, unit: "", range: "≥ 100", key: "green" },
        { label: "🔵 Blue", value: blue, unit: "", range: "≥ 100", key: "blue" },
      ].map((sensor) => (
        <div style={cardStyle} key={sensor.key}>
          <div style={labelStyle}>{sensor.label}</div>
          <div style={valueBox}>
            {sensor.value} {sensor.unit}
          </div>
          <div style={rangeText}>Safe Range: {sensor.range}</div>
          <span style={badge(getStatus(sensor.key))}>{getStatus(sensor.key)}</span>
        </div>
      ))}
    </div>
  );
}
